// ====================================================
// 1. Normalização do payload de entrada
// ====================================================
// Aceita:
//   a) { "cves": ["CVE-2024-1234", "CVE-2025-9999"] }
//   b) ["CVE-2024-1234", "CVE-2025-9999"]
//   c) { "cves": [{ "id": "...", "asset": "...", "exposure": "internet", "criticality": "critical" }, ...] }
//
// Suporta também metadata opcional:
//   { "meta": { "requestor": "carlos.domingues", "source": "openvas-scan-2026-05-19" }, "cves": [...] }

const rawBody = $input.first().json.body ?? $input.first().json;
let list = [];
let meta = {};

if (Array.isArray(rawBody)) {
  list = rawBody;
} else if (Array.isArray(rawBody.cves)) {
  list = rawBody.cves;
  meta = rawBody.meta ?? {};
} else if (rawBody.cve) {
  list = [rawBody.cve];
} else {
  throw new Error('Payload inválido. Esperado: { cves: [...] } ou array de CVEs.');
}

if (list.length === 0) throw new Error('Lista de CVEs vazia.');
if (list.length > 300) throw new Error('Lote demasiado grande (>200). Dividir em vários pedidos.');

const requestId = `req-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
const cvePattern = /^CVE-\d{4}-\d{4,}$/i;

const items = list.map((entry) => {
  let cve, asset = null, exposure = 'internal', criticality = 'medium';
  if (typeof entry === 'string') {
    cve = entry.trim().toUpperCase();
  } else if (typeof entry === 'object' && entry !== null) {
    cve = (entry.id || entry.cve || '').trim().toUpperCase();
    asset = entry.asset ?? null;
    exposure = (entry.exposure ?? 'internal').toLowerCase();
    criticality = (entry.criticality ?? 'medium').toLowerCase();
  }
  if (!cve || !cvePattern.test(cve)) {
    throw new Error(`Entrada inválida: '${JSON.stringify(entry)}'. Esperado formato CVE-YYYY-NNNN.`);
  }
  return {
    json: {
      cve, asset, exposure, criticality,
      _request_id: requestId,
      _meta: meta
    }
  };
});

return items;

// Heurística: presença do CVE em contexto de exploit na página
const html = $json.data ?? $json.body ?? '';
const cve = $('Normalizar payload').item.json.cve;
const hasExploit = typeof html === 'string'
  && html.includes(cve)
  && /exploit|<table|exploits-table/i.test(html);
return [{
  json: {
    cve,
    exploit_db_match: hasExploit,
    exploit_db_url: `https://www.exploit-db.com/search?cve=${cve.replace('CVE-','')}`
  }
}];

// ====================================================
// Consolidação + Risk Score — processa TODOS os items
// (compatível com modo 'Run Once for All Items')
// ====================================================
const allGrouped  = $input.all().map(i => i.json);
const allOriginal = $('Normalizar payload').all().map(i => i.json);

const critMap = { critical: 2.0, high: 1.5, medium: 1.0, low: 0.7 };
const expMap  = { internet: 2.0, dmz: 1.5, internal: 1.0 };

const results = [];

for (const grouped of allGrouped) {
  const cve      = grouped.cve;
  const original = allOriginal.find(i => i.cve === cve) ?? {};

  // --- NVD ---
  const nvdRaw   = grouped._nvd ?? {};
  const nvdEntry = nvdRaw?.vulnerabilities?.[0]?.cve ?? null;

  let cvssScore=null, cvssVector=null, cvssVersion=null, cvssSeverity=null;
  let cwes=[], description=null, published=null, lastModified=null, references=[];

  if (nvdEntry) {
    description  = (nvdEntry.descriptions ?? []).find(d => d.lang === 'en')?.value ?? null;
    published    = nvdEntry.published ?? null;
    lastModified = nvdEntry.lastModified ?? null;
    references   = (nvdEntry.references ?? []).map(r => r.url).slice(0, 10);
    cwes = (nvdEntry.weaknesses ?? [])
      .flatMap(w => (w.description ?? []).map(d => d.value))
      .filter(v => /^CWE-/i.test(v));
    const m = nvdEntry.metrics ?? {};
    const v31 = m.cvssMetricV31?.[0]?.cvssData;
    const v30 = m.cvssMetricV30?.[0]?.cvssData;
    const v2  = m.cvssMetricV2?.[0]?.cvssData;
    const chosen = v31 || v30 || v2;
    if (chosen) {
      cvssScore    = chosen.baseScore;
      cvssVector   = chosen.vectorString;
      cvssVersion  = chosen.version;
      cvssSeverity = m.cvssMetricV31?.[0]?.cvssData?.baseSeverity
        || m.cvssMetricV30?.[0]?.cvssData?.baseSeverity
        || m.cvssMetricV2?.[0]?.baseSeverity
        || null;
    }
  }

  // --- EPSS ---
  const epssRaw        = grouped._epss ?? {};
  const epssEntry      = epssRaw?.data?.[0] ?? null;
  const epssScore      = epssEntry ? parseFloat(epssEntry.epss) : null;
  const epssPercentile = epssEntry ? parseFloat(epssEntry.percentile) : null;

  // --- KEV ---
  const kev = grouped._kev ?? {};

  // --- ExploitDB ---
  const edb = grouped._edb ?? {};

  // --- Risk Score ---
  const hasExploit   = !!(edb.exploit_db_match) || (epssScore !== null && epssScore >= 0.5) || !!kev.in_kev;
  const exploitMult  = hasExploit ? 1.5 : 1.0;
  const exposureMult = expMap[original.exposure]     ?? 1.0;
  const critMult     = critMap[original.criticality] ?? 1.0;

  let riskScore = Math.round((cvssScore ?? 0) * exploitMult * exposureMult * critMult * 100) / 100;

  let band = 'Baixo', sla = 'Backlog';
  if (riskScore >= 35)      { band = 'Crítico'; sla = '24-72h'; }
  else if (riskScore >= 20) { band = 'Alto';    sla = '7 dias'; }
  else if (riskScore >= 10) { band = 'Médio';   sla = '30 dias'; }
  if (kev.in_kev)           { band = 'Crítico'; sla = '24-72h'; }

  results.push({
    json: {
      cve,
      asset:             original.asset        ?? null,
      exposure:          original.exposure      ?? null,
      asset_criticality: original.criticality   ?? null,
      _request_id:       original._request_id   ?? null,
      _meta:             original._meta         ?? {},
      nvd: {
        description, published, last_modified: lastModified,
        cvss_score: cvssScore, cvss_vector: cvssVector,
        cvss_version: cvssVersion, cvss_severity: cvssSeverity,
        cwes, references_top: references
      },
      epss: { score: epssScore, percentile: epssPercentile },
      kev: {
        in_kev:           !!kev.in_kev,
        date_added:       kev.kev_date_added      ?? null,
        due_date:         kev.kev_due_date        ?? null,
        known_ransomware: !!kev.kev_known_ransomware,
        required_action:  kev.kev_required_action ?? null
      },
      exploit_db: { match: !!edb.exploit_db_match, url: edb.exploit_db_url ?? null },
      risk: {
        exploit_available: hasExploit,
        multipliers: { exploit: exploitMult, exposure: exposureMult, criticality: critMult },
        risk_score: riskScore,
        band, sla
      }
    }
  });
}

return results;

// Merge análise IA — resposta única do Ollama com array de análises
const ollamaResponse = $json?.response ?? $json?.text ?? '[]';
const prepNode = $('Preparar prompt IA').first().json;
const allEnriched = prepNode._all_enriched ?? [];

let analyses = [];
try {
  const parsed = JSON.parse(ollamaResponse);
  analyses = Array.isArray(parsed) ? parsed : [parsed];
} catch (e) {
  // Se o parse falhar, devolver todos os CVEs com erro
  return allEnriched.map(item => ({
    json: {
      ...item,
      ai_analysis: {
        resumo: null, impacto_negocio: null, accao_recomendada: null,
        prioridade_sugerida: null, justificacao: null,
        _parse_error: e.message, _raw: ollamaResponse
      },
      _enriched_at: new Date().toISOString()
    }
  }));
}

// Match por cve entre análise IA e dados enriquecidos
return allEnriched.map(item => {
  const ai = analyses.find(a => (a.cve ?? '').toUpperCase() === item.cve.toUpperCase())
          ?? analyses[allEnriched.indexOf(item)]
          ?? {};
  return {
    json: {
      ...item,
      ai_analysis: {
        resumo:              ai.resumo              ?? null,
        impacto_negocio:     ai.impacto_negocio     ?? null,
        accao_recomendada:   ai.accao_recomendada   ?? null,
        prioridade_sugerida: ai.prioridade_sugerida ?? null,
        justificacao:        ai.justificacao        ?? null
      },
      _enriched_at: new Date().toISOString()
    }
  };
});

// Agregação final
const items = $input.all().map(i => i.json);
const summary = {
  total: items.length,
  critical: items.filter(i => i.risk.band === 'Crítico').length,
  high:     items.filter(i => i.risk.band === 'Alto').length,
  medium:   items.filter(i => i.risk.band === 'Médio').length,
  low:      items.filter(i => i.risk.band === 'Baixo').length,
  in_kev:   items.filter(i => i.kev.in_kev).length,
  with_exploit: items.filter(i => i.risk.exploit_available).length,
  ransomware:   items.filter(i => i.kev.known_ransomware).length
};
return [{
  json: {
    request_id: items[0]?._request_id ?? null,
    generated_at: new Date().toISOString(),
    meta: items[0]?._meta ?? {},
    summary,
    findings: items
  }
}];

// ====================================================
// 3. Gerar ficheiro JSON (binário) com o output completo
// ====================================================
const payload = $input.first().json;
const json = JSON.stringify(payload, null, 2);
const buffer = Buffer.from(json, 'utf-8');
const ts = new Date().toISOString().replace(/[:.]/g, '-');
const filename = `cve_enrichment_${ts}.json`;

return [{
  json: payload,
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'application/json',
      fileName: filename,
      fileExtension: 'json'
    }
  }
}];

// Group by CVE — reagrupa todos os ramos e faz lookup KEV interno
// Recebe: NVD×N + EPSS×N + CISA KEV×1 (catálogo completo) + ExploitDB×N
const all = $input.all().map(i => i.json);

// 1. Separar o catálogo KEV
// FIX v5: deteção por catalogVersion (campo exclusivo da KEV API) — robusto a respostas parciais
// Fallback: array vulnerabilities com >10 entradas (compatibilidade)
const kevCatalog = all.find(item => item.catalogVersion !== undefined)
  ?? all.find(item => Array.isArray(item.vulnerabilities) && item.vulnerabilities.length > 10);
const kevVulns = kevCatalog?.vulnerabilities ?? [];

// 2. Descobrir lista de CVEs pelo EPSS (campo data[0].cve garantido)
const cveSet = new Set();
for (const item of all) {
  if (Array.isArray(item.data) && item.data[0]?.cve) {
    cveSet.add(item.data[0].cve.toUpperCase());
  }
}
const cveList = [...cveSet];

// 3. Inicializar grouped
const grouped = {};
for (const cve of cveList) {
  grouped[cve] = { cve, _nvd: {}, _epss: {}, _kev: {}, _edb: {} };
}

// 4. Distribuir NVD, EPSS, ExploitDB
for (const item of all) {
  // Ignorar o catálogo KEV (já tratado acima)
  if (item.catalogVersion !== undefined) continue;
  if (Array.isArray(item.vulnerabilities) && item.vulnerabilities.length > 10) continue;

  // NVD: tem totalResults ou vulnerabilities (pequeno, 1 CVE)
  if (item.totalResults !== undefined || item.vulnerabilities !== undefined) {
    const id = (item.vulnerabilities?.[0]?.cve?.id ?? '').toUpperCase();
    if (id && grouped[id]) {
      grouped[id]._nvd = item;
    } else {
      const fallback = cveList.find(c => Object.keys(grouped[c]._nvd).length === 0);
      if (fallback) grouped[fallback]._nvd = item;
    }
    continue;
  }
  // EPSS
  if (Array.isArray(item.data) && item.data[0]?.cve) {
    const cve = item.data[0].cve.toUpperCase();
    if (grouped[cve]) grouped[cve]._epss = item;
    continue;
  }
  // ExploitDB
  if (item.exploit_db_match !== undefined && item.cve) {
    const cve = item.cve.toUpperCase();
    if (grouped[cve]) grouped[cve]._edb = item;
    continue;
  }
}

// 5. Lookup KEV interno para cada CVE
for (const cve of cveList) {
  const entry = kevVulns.find(v => (v.cveID ?? '').toUpperCase() === cve);
  grouped[cve]._kev = {
    cve,
    in_kev:                !!entry,
    kev_date_added:        entry?.dateAdded         ?? null,
    kev_due_date:          entry?.dueDate           ?? null,
    kev_vendor:            entry?.vendorProject     ?? null,
    kev_product:           entry?.product           ?? null,
    kev_short_description: entry?.shortDescription  ?? null,
    kev_required_action:   entry?.requiredAction    ?? null,
    kev_known_ransomware:  entry?.knownRansomwareCampaignUse === 'Known'
  };
}

return Object.values(grouped).map(g => ({ json: g }));
